function Portfolio() {
  const [pos, setPos] = useState(0);
  const trackRef = useRef(null);

  const move = (dir) => {
    const track = trackRef.current;
    if (!track) return;
    const items = track.querySelectorAll(".o360-carousel-item");
    const gap = 24;
    const itemW = items[1].offsetWidth + gap;
    const maxPos = (items.length - 2) * itemW;
    const newPos = Math.max(0, Math.min(pos + dir * itemW, maxPos));
    setPos(newPos);
  };

  return (
    <section className="o360-portfolio" id="portfolio">
      <div className="o360-portfolio-header">
        <p className="o360-section-label">Portfólio — Projetos selecionados</p>
        <div className="o360-carousel-nav">
          <button className="o360-carousel-btn" onClick={() => move(-1)}>&#8592;</button>
          <button className="o360-carousel-btn" onClick={() => move(1)}>&#8594;</button>
        </div>
      </div>
      <div className="o360-carousel-wrap">
        <div
          className="o360-carousel-track"
          ref={trackRef}
          style={{ transform: `translateX(-${pos}px)` }}
        >
          {projects.map((p, i) => (
            <div className="o360-carousel-item" key={p.key}>
              <div className="o360-c-img">
                <img src={IMGS[p.key]} alt={p.label} />
              </div>
              <p className="o360-item-label">{p.label}</p>
              <p className="o360-item-sub">{p.sub}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

